mapper.select:
SELECT DISTINCT f.id, f.name, f.description, f.category_id, f.image_url, f.price, f.rating, f.rating_count, f.status, f.created_by, f.created_at, f.updated_at, fc.id AS cat_id, fc.name AS cat_name, fc.description AS cat_description, ft.id AS tag_id, ft.name AS tag_name, ft.color AS tag_color, (SELECT COUNT(*) FROM comments c WHERE c.food_id = f.id) AS comments_count FROM foods f LEFT JOIN food_categories fc ON f.category_id = fc.id LEFT JOIN food_tag_relations ftr ON f.id = ftr.food_id LEFT JOIN food_tags ft ON ftr.tag_id = ft.id
AND (f.name LIKE CONCAT('%', #{keyword}, '%') OR f.description LIKE CONCAT('%', #{keyword}, '%'))
AND f.category_id = #{categoryId}
AND f.status = #{status}
ORDER BY f.created_at DESC
